const { randomUUID } = require('node:crypto');
const projects = require('../projects/service').getAll();
const members = {};

function create(projectId, memberData) {
  const project = projects.find(p => p.id === projectId);
  if (!project) {
    throw { code: 'not_found', message: 'Project not found' };
  }
  if (members[projectId] && members[projectId].some(m => m.userId === memberData.userId)) {
    throw { code: 'duplicate', message: 'Member already exists in project' };
  }
  const memberId = randomUUID();
  if (!members[projectId]) {
    members[projectId] = [];
  }
  members[projectId].push({ ...memberData, id: memberId });
  return members[projectId][members[projectId].length - 1];
}

function getAll(projectId) {
  const projectMembers = members[projectId] || [];
  return projectMembers;
}

module.exports = { create, getAll };
