const projects = require('../projects/service').getAll();
const tasks = {};

function create(projectId, taskData) {
  const project = projects.find(p => p.id === projectId);
  if (!project) {
    throw { code: 'not_found', message: 'Project not found' };
  }
  const taskId = randomUUID();
  if (!tasks[projectId]) {
    tasks[projectId] = [];
  }
  tasks[projectId].push({ ...taskData, id: taskId, status: 'pending' });
  return tasks[projectId][tasks[projectId].length - 1];
}

function getAll(projectId, status) {
  const projectTasks = tasks[projectId] || [];
  if (status) {
    return projectTasks.filter(task => task.status === status);
  }
  return projectTasks;
}

function update(projectId, taskId, taskData) {
  const projectTasks = tasks[projectId];
  if (!projectTasks) {
    throw { code: 'not_found', message: 'Project not found' };
  }
  const taskIndex = projectTasks.findIndex(task => task.id === taskId);
  if (taskIndex === -1) {
    throw { code: 'not_found', message: 'Task not found' };
  }
  tasks[projectId][taskIndex] = { ...projectTasks[taskIndex], ...taskData };
  return tasks[projectId][taskIndex];
}

