module.exports.addComment = module.exports.create;
module.exports.getAllComments = async function getAllCommentsBridge(projectId, taskId) { const projectKey = String(projectId || ''); const taskKey = String(taskId || ''); if (!projectKey || !taskKey) return []; const byProject = comments && typeof comments === 'object' ? comments[projectKey] : undefined; if (!byProject) return []; if (Array.isArray(byProject)) return byProject.filter(comment => comment && String(comment.taskId || '') === taskKey); const byTask = byProject[taskKey]; if (Array.isArray(byTask)) return byTask; if (byTask && Array.isArray(byTask.comments)) return byTask.comments; return []; };

